import{_ as t,o as i,c as a,a3 as s}from"./chunks/framework.LBeL10WQ.js";const u=JSON.parse('{"title":"Logistics & Insertion","description":"","frontmatter":{"title":"Logistics & Insertion"},"headers":[],"relativePath":"en/publishers/sponsored-mail/logistics.md","filePath":"en/publishers/sponsored-mail/logistics.md"}'),o={name:"en/publishers/sponsored-mail/logistics.md"};function r(n,e,l,d,c,p){return i(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="logistics-operations" tabindex="-1">Logistics Operations <a class="header-anchor" href="#logistics-operations" aria-label="Permalink to &quot;Logistics Operations&quot;">​</a></h1><p>From pallet reception to the customer unboxing experience.</p><hr><h2 id="_1-receiving-materials" tabindex="-1">1. Receiving materials <a class="header-anchor" href="#_1-receiving-materials" aria-label="Permalink to &quot;1. Receiving materials&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Check upon arrival</h3><p>The materials (flyers, samples) are delivered to your warehouse address provided on the platform.</p><ul><li>Check the condition of the pallets and boxes.</li><li>Verify that the quantity matches the delivery note (BL).</li></ul></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Confirmation of Receipt</h3><p><strong>Mandatory action:</strong> Log in to <a href="https://app.getinside.media/">app.getinside.media</a> and click on <strong>&quot;Validate reception&quot;</strong>.</p><p>This notifies the Advertiser that the merchandise has safely arrived and is ready for distribution.</p></div></div><div class="warning custom-block"><p class="custom-block-title">Delivery problem?</p><p>If the materials are damaged, take photos and report it immediately to <a href="mailto:logistique@getinside.fr" target="_blank" rel="noreferrer">logistique@getinside.fr</a> <strong>before any distribution</strong>.</p></div><hr><h2 id="_2-insertion-best-practices" tabindex="-1">2. Insertion best practices <a class="header-anchor" href="#_2-insertion-best-practices" aria-label="Permalink to &quot;2. Insertion best practices&quot;">​</a></h2><p>The value of the Parcel Insert relies on the unboxing experience. To ensure Advertiser satisfaction, follow these golden rules.</p><h3 id="✅-the-on-top-rule" tabindex="-1">✅ The &quot;On-Top&quot; Rule <a class="header-anchor" href="#✅-the-on-top-rule" aria-label="Permalink to &quot;✅ The &quot;On-Top&quot; Rule&quot;">​</a></h3><p>The advertising material must imperatively be placed <strong>on top of the products</strong>, face up. It must be the first thing the customer sees.</p><p><img src="/handbook/images/asile-colis-do-dont.webp" alt="Parcel insert best practices"></p><div class="gi-value-grid"><div class="gi-value-card"><strong>📄 Invoice management</strong><p>If you insert a packing slip or a paper invoice: place the offer **on top**. It must never be hidden inside a folded document.</p></div><div class="gi-value-card"><strong>🚫 Exclusions &amp; Quality</strong><ul><li><strong>Competition:</strong> Never two competing offers in the same parcel.</li><li><strong>Condition:</strong> Do not insert a crumpled or dog-eared flyer.</li></ul></div></div><h2 id="_3-storage" tabindex="-1">3. Storage <a class="header-anchor" href="#_3-storage" aria-label="Permalink to &quot;3. Storage&quot;">​</a></h2><p>The materials must be stored in a dry and clean place (away from humidity and dust) to prevent any deterioration before insertion.</p>',16)])])}const g=t(o,[["render",r]]);export{u as __pageData,g as default};
